  .map((announcementStr, index) => {
    let announcement = null;
    const str = announcementStr?.trim();

    if (str) {
      // 상대 URL 그대로 사용
      announcement = str;
    }

    if (announcement) {
      announcement = baseUrl.replace(/\/$/, '') + announcement; // 절대 URL 생성
    }

    let dateStr = dates[index] || null;
    if (dateStr) {
      dateStr = dateStr.replace(/\s+/g, '').replace(/\.$/, '');
      const dateMatch = dateStr.match(/(\d{4})[.\-](\d{1,2})[.\-](\d{1,2})/);
      if (dateMatch) {
        const y = dateMatch[1];
        const m = dateMatch[2].padStart(2, '0');
        const d = dateMatch[3].padStart(2, '0');
        dateStr = `${y}-${m}-${d}`;
      } else dateStr = null;
